<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Mini Spreadsheet</title>
<style>
  body {
    font-family: monospace;
    margin: 20px;
    background: #f4f4f4;
  }
  #app {
    width: 640px;
    min-height: 420px;
    background: #fff;
    border: 1px solid #ccc;
    padding: 10px;
    box-sizing: border-box;
  }
  table {
    border-collapse: collapse;
    margin-bottom: 10px;
  }
  th, td {
    border: 1px solid #999;
    width: 56px;
    height: 28px;
    text-align: center;
    padding: 0;
  }
  th {
    background: #e8e8e8;
    font-weight: bold;
  }
  input.cell {
    width: 100%;
    height: 100%;
    box-sizing: border-box;
    border: none;
    text-align: center;
    font-family: monospace;
    font-size: 13px;
    background: transparent;
  }
  input.cell:focus {
    background: #fffbe6;
    outline: 2px solid #4a90e2;
  }
  #controls {
    margin-top: 10px;
  }
  button {
    font-family: monospace;
    padding: 6px 10px;
    cursor: pointer;
  }
  #csv {
    width: 100%;
    height: 120px;
    margin-top: 8px;
    font-family: monospace;
    font-size: 12px;
  }
</style>
</head>
<body>
<div id="app">
  <table id="grid"></table>
  <div id="controls">
    <button id="export">Export CSV</button>
    <textarea id="csv" readonly placeholder="CSV output appears here"></textarea>
  </div>
</div>

<script>
(function () {
  const COLS = "ABCDEFGHIJ".split("");
  const ROWS = 10;
  const grid = document.getElementById("grid");

  // raw text storage
  const rawText = {};
  const inputs = {};

  // build headers + grid
  const headRow = document.createElement("tr");
  headRow.appendChild(document.createElement("th")); // corner
  COLS.forEach(c => {
    const th = document.createElement("th");
    th.textContent = c;
    headRow.appendChild(th);
  });
  grid.appendChild(headRow);

  for (let r = 1; r <= ROWS; r++) {
    const tr = document.createElement("tr");
    const rh = document.createElement("th");
    rh.textContent = r;
    tr.appendChild(rh);
    COLS.forEach(c => {
      const id = c + r;
      const td = document.createElement("td");
      const inp = document.createElement("input");
      inp.className = "cell";
      inp.id = "cell-" + id;
      inp.value = "";
      rawText[id] = "";
      inputs[id] = inp;

      inp.addEventListener("focus", () => {
        inp.value = rawText[id];
      });
      inp.addEventListener("blur", () => {
        setCell(id, inp.value);
        inp.value = getCell(id);
      });
      inp.addEventListener("keydown", (e) => {
        if (e.key === "Enter") {
          inp.blur();
        }
      });

      td.appendChild(inp);
      tr.appendChild(td);
    });
    grid.appendChild(tr);
  }

  function setCell(id, text) {
    rawText[id] = text;
    recalcAll();
    // refresh display if not focused
    if (document.activeElement !== inputs[id]) {
      inputs[id].value = getCell(id);
    }
  }

  function getCell(id) {
    const v = computedCache[id];
    if (v === "#CYCLE") return "#CYCLE";
    if (v === "#ERR") return "#ERR";
    if (v === "" || v === null || v === undefined) return "";
    if (typeof v === "number") {
      return String(v);
    }
    return String(v);
  }

  function raw(id) {
    return rawText[id] || "";
  }

  // ---- evaluation engine ----
  let computedCache = {};

  function colRowFromRef(ref) {
    const m = ref.match(/^([A-J])([1-9]|10)$/);
    if (!m) return null;
    return m[1] + m[2];
  }

  function tokenize(expr) {
    const tokens = [];
    let i = 0;
    while (i < expr.length) {
      const ch = expr[i];
      if (ch === ' ') { i++; continue; }
      if (ch >= '0' && ch <= '9' || ch === '.') {
        let num = '';
        while (i < expr.length && ((expr[i] >= '0' && expr[i] <= '9') || expr[i] === '.')) {
          num += expr[i++];
        }
        tokens.push({ t: 'num', v: parseFloat(num) });
        continue;
      }
      if (ch >= 'A' && ch <= 'J') {
        let ref = '';
        while (i < expr.length && ((expr[i] >= 'A' && expr[i] <= 'J') || (expr[i] >= '0' && expr[i] <= '9'))) {
          ref += expr[i++];
        }
        const id = colRowFromRef(ref);
        if (!id) throw new Error("bad ref");
        tokens.push({ t: 'ref', v: id });
        continue;
      }
      if ("+-*/()".includes(ch)) {
        tokens.push({ t: 'op', v: ch });
        i++;
        continue;
      }
      throw new Error("bad char");
    }
    return tokens;
  }

  function parseTokens(tokens) {
    let pos = 0;
    function peek() { return tokens[pos]; }
    function next() { return tokens[pos++]; }

    function parseExpr() {
      let left = parseTerm();
      while (peek() && peek().t === 'op' && (peek().v === '+' || peek().v === '-')) {
        const op = next().v;
        const right = parseTerm();
        left = op === '+' ? left + right : left - right;
      }
      return left;
    }
    function parseTerm() {
      let left = parseFactor();
      while (peek() && peek().t === 'op' && (peek().v === '*' || peek().v === '/')) {
        const op = next().v;
        const right = parseFactor();
        left = op === '*' ? left * right : left / right;
      }
      return left;
    }
    function parseFactor() {
      const tk = peek();
      if (!tk) throw new Error("unexpected end");
      if (tk.t === 'num') { next(); return tk.v; }
      if (tk.t === 'ref') {
        next();
        const val = evalCell(tk.v);
        if (val === "#ERR" || val === "#CYCLE") throw new Error("cell err");
        return val;
      }
      if (tk.t === 'op' && tk.v === '(') {
        next();
        const v = parseExpr();
        if (!peek() || peek().v !== ')') throw new Error("no paren");
        next();
        return v;
      }
      if (tk.t === 'op' && (tk.v === '+' || tk.v === '-')) {
        const op = next().v;
        const v = parseFactor();
        return op === '-' ? -v : v;
      }
      throw new Error("bad factor");
    }

    const result = parseExpr();
    if (pos < tokens.length) throw new Error("trailing");
    return result;
  }

  const visiting = new Set();
  const done = {};

  function evalCell(id) {
    if (done.hasOwnProperty(id)) return done[id];
    if (visiting.has(id)) return "#CYCLE";
    visiting.add(id);

    const txt = rawText[id] || "";
    let val;
    if (txt === "") {
      val = 0;
    } else if (txt[0] === '=') {
      try {
        const tokens = tokenize(txt.slice(1));
        val = parseTokens(tokens);
        if (typeof val !== 'number' || !isFinite(val)) val = "#ERR";
      } catch (e) {
        val = "#ERR";
      }
    } else {
      const n = parseFloat(txt);
      if (!isNaN(n) && String(n) === txt.trim()) val = n;
      else val = txt;
    }

    visiting.delete(id);
    done[id] = val;
    return val;
  }

  function recalcAll() {
    for (const k in visiting) visiting.delete(k);
    for (const k in done) delete done[k];
    const all = [];
    COLS.forEach(c => {
      for (let r = 1; r <= ROWS; r++) all.push(c + r);
    });
    all.forEach(evalCell);
    computedCache = Object.assign({}, done);
  }

  // export
  document.getElementById("export").addEventListener("click", () => {
    recalcAll();
    const lines = [];
    for (let r = 1; r <= ROWS; r++) {
      const row = [];
      COLS.forEach(c => {
        row.push(getCell(c + r));
      });
      lines.push(row.join(","));
    }
    document.getElementById("csv").value = lines.join("\n");
  });

  // API
  window.sheet = {
    set: function (id, text) {
      setCell(id, text);
    },
    get: function (id) {
      return getCell(id);
    },
    raw: function (id) {
      return raw(id);
    }
  };

  // initial calc
  recalcAll();
  COLS.forEach(c => {
    for (let r = 1; r <= ROWS; r++) {
      const id = c + r;
      if (document.activeElement !== inputs[id]) {
        inputs[id].value = getCell(id);
      }
    }
  });
})();
</script>
</body>
</html>
